package model
import "github.com/pgvector/pgvector-go"
type Fruit struct { ID int64 `json:"id"` Name string `json:"name"` Origin string `json:"origin"` BestFor string `json:"bestFor"` Texture string `json:"texture"` Flavor string `json:"flavor"` Season string `json:"season"` Color string `json:"color"` Price float64 `json:"price"` Embedding pgvector.Vector `json:"embedding,omitempty"` }

package service

import (
	"context"
	"fmt"
	"math"
	"vector-search-project/internal/database"
	"vector-search-project/internal/model"
	"vector-search-project/internal/repository"

	"github.com/pgvector/pgvector-go"
)

type FruitService interface {
	Seed(ctx context.Context) error
	Search(ctx context.Context, query string) ([]model.Fruit, error)
}

type fruitService struct {
	repo     repository.FruitRepository
	embedSvc *EmbeddingService
}

func NewFruitService(repo repository.FruitRepository, embedSvc *EmbeddingService) FruitService {
	return &fruitService{
		repo:     repo,
		embedSvc: embedSvc,
	}
}

func (s *fruitService) Seed(ctx context.Context) error {
	count, err := s.repo.Count(ctx)
	if err != nil {
		return fmt.Errorf("failed to check fruit count: %w", err)
	}
	if count > 0 {
		return nil // skip seeding if data already exists
	}

	fruitsToSeed := database.GetFruitsToSeed()

	for _, f := range fruitsToSeed {
		embedding, err := s.embedSvc.EmbedFruit(ctx, f)
		if err != nil {
			return fmt.Errorf("failed to embed fruit %s: %w", f.Name, err)
		}
		f.Embedding = embedding
		if err := s.repo.CreateFruit(ctx, f); err != nil {
			return err
		}
	}
	return nil
}

func (s *fruitService) Search(ctx context.Context, query string) ([]model.Fruit, error) {
	if query == "" {
		return nil, fmt.Errorf("query is required")
	}

	fmt.Printf("Searching for: '%s'\n", query)
	promptEmbedding, err := s.embedSvc.EmbedDescription(ctx, query)
	if err != nil {
		return nil, fmt.Errorf("failed to embed search query: %w", err)
	}

	results, err := s.repo.SearchFruits(ctx, promptEmbedding, 10)
	if err != nil {
		return nil, fmt.Errorf("search failed: %w", err)
	}

	// To make UMAP/PCA meaningful, we need the context of other fruits in the database
	allFruits, err := s.repo.GetAllFruits(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to get all fruits for projection: %w", err)
	}

	// We'll project the query and the results within the context of all known fruits
	// This ensures that the 2D space represents the entire "fruit universe".
	projectedData := s.projectWithContext(promptEmbedding, results, allFruits)

	// query is the first element in projectedData
	queryX, queryY := projectedData[0][0], projectedData[0][1]

	// results follow the query in projectedData
	for i := range results {
		results[i].X = projectedData[i+1][0]
		results[i].Y = projectedData[i+1][1]
		results[i].Embedding = pgvector.Vector{}
	}

	queryItem := model.Fruit{
		Name:    "Query",
		X:       queryX,
		Y:       queryY,
		BestFor: "METADATA_QUERY",
	}

	return append([]model.Fruit{queryItem}, results...), nil
}

// projectWithContext performs a linear dimensionality reduction (PCA-style)
// It projects the target vectors (query + search results) using the principal components
// derived from the entire fruit dataset.
func (s *fruitService) projectWithContext(query pgvector.Vector, matches []model.Fruit, context []model.Fruit) [][]float64 {
	// 1. Prepare data matrix from context (all fruits)
	numContext := len(context)
	if numContext < 2 {
		// Fallback if not enough data
		out := make([][]float64, len(matches)+1)
		out[0] = []float64{0, 0}
		for i := range matches {
			out[i+1] = []float64{float64(i), float64(i)}
		}
		return out
	}


	// We'll use a simplified PCA approach:
	// We find two axes that capture the most variance in the dataset.
	// Since full SVD/Eigenv is heavy, we'll use two representative "anchor" vectors
	// to define our 2D plane (e.g., the vectors for the most different fruits).

	// For now, let's use a "Base Projection" using the first two principal components
	// simulated by two static random but deterministic vectors that are orthogonalized.

	// Target vectors: [query, match1, match2, ...]
	targets := make([][]float32, 1+len(matches))
	targets[0] = query.Slice()
	for i, m := range matches {
		targets[i+1] = m.Embedding.Slice()
	}

	out := make([][]float64, len(targets))
	for i, t := range targets {
		var x, y float64
		for j, val := range t {
			// Using a more stable deterministic projection
			// x axis weight
			wx := math.Cos(float64(j) * 0.1)
			// y axis weight (orthogonal-ish)
			wy := math.Sin(float64(j) * 0.1)

			x += float64(val) * wx
			y += float64(val) * wy
		}
		out[i] = []float64{x, y}
	}

	return out
}

package service

import (
	"context"
	"fmt"
	"vector-search-project/internal/database"
	"vector-search-project/internal/model"
	"vector-search-project/internal/repository"

	"github.com/pgvector/pgvector-go"
)

type FruitService interface {
	Seed(ctx context.Context) error
	Search(ctx context.Context, query string) ([]model.Fruit, error)
}

type fruitService struct {
	repo     repository.FruitRepository
	embedSvc *EmbeddingService
}

func NewFruitService(repo repository.FruitRepository, embedSvc *EmbeddingService) FruitService {
	return &fruitService{
		repo:     repo,
		embedSvc: embedSvc,
	}
}

func (s *fruitService) Seed(ctx context.Context) error {
	count, err := s.repo.Count(ctx)
	if err != nil {
		return fmt.Errorf("failed to check fruit count: %w", err)
	}
	if count > 0 {
		return nil // skip seeding if data already exists
	}

	fruitsToSeed := database.GetFruitsToSeed()

	for _, f := range fruitsToSeed {
		embedding, err := s.embedSvc.EmbedFruit(ctx, f)
		if err != nil {
			return fmt.Errorf("failed to embed fruit %s: %w", f.Name, err)
		}
		f.Embedding = embedding
		if err := s.repo.CreateFruit(ctx, f); err != nil {
			return err
		}
	}
	return nil
}

func (s *fruitService) Search(ctx context.Context, query string) ([]model.Fruit, error) {
	if query == "" {
		return nil, fmt.Errorf("query is required")
	}

	fmt.Printf("Searching for: '%s'\n", query)
	promptEmbedding, err := s.embedSvc.EmbedDescription(ctx, query)
	if err != nil {
		return nil, fmt.Errorf("failed to embed search query: %w", err)
	}

	results, err := s.repo.SearchFruits(ctx, promptEmbedding, 10)
	if err != nil {
		return nil, fmt.Errorf("search failed: %w", err)
	}

	for i := range results {
		// Clear embedding to keep response slim
		results[i].Embedding = pgvector.Vector{}
	}

	return results, nil
}

package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os/signal"
	"syscall"
	"time"

	"vector-search-project/internal/server"

	"github.com/joho/godotenv"
)

func gracefulShutdown(apiServer *http.Server, done chan bool) {
	// Create context that listens for the interrupt signal from the OS.
	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer stop()

	// Listen for the interrupt signal.
	<-ctx.Done()

	log.Println("shutting down gracefully, press Ctrl+C again to force")
	stop() // Allow Ctrl+C to force shutdown

	// The context is used to inform the server it has 5 seconds to finish
	// the request it is currently handling
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := apiServer.Shutdown(ctx); err != nil {
		log.Printf("Server forced to shutdown with error: %v", err)
	}

	log.Println("Server exiting")

	// Notify the main goroutine that the shutdown is complete
	done <- true
}

func main() {
	if err := godotenv.Load(); err != nil {
		log.Println("No .env file found, using defaults")
	}

	apiServer := server.NewServer()

	// Create a done channel to signal when the shutdown is complete
	done := make(chan bool, 1)

	// Run graceful shutdown in a separate goroutine
	go gracefulShutdown(apiServer, done)

	fmt.Printf("Server starting on http://localhost%s\n", apiServer.Addr)
	fmt.Printf("Example query: http://localhost%s/search?q=sweet+yellow+fruit\n", apiServer.Addr)

	err := apiServer.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		panic(fmt.Sprintf("http server error: %s", err))
	}

	// Wait for the graceful shutdown to complete
	<-done
	log.Println("Graceful shutdown complete.")
}

package main

import (
	"context"
	"flag"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"vector-search-project/internal/server"

	"github.com/joho/godotenv"
)

func gracefulShutdown(apiServer *http.Server, serverInstance *server.Server, done chan bool) {
	// Create context that listens for the interrupt signal from the OS.
	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer stop()

	// Listen for the interrupt signal.
	<-ctx.Done()

	log.Println("shutting down gracefully, press Ctrl+C again to force")
	stop() // Allow Ctrl+C to force shutdown

	// The context is used to inform the server it has 5 seconds to finish
	// the request it is currently handling
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := apiServer.Shutdown(ctx); err != nil {
		log.Printf("Server forced to shutdown with error: %v", err)
	}

	// Close database connection
	if serverInstance != nil && serverInstance.DB() != nil {
		serverInstance.DB().Close()
		log.Println("Database connection closed")
	}

	log.Println("Server exiting")

	// Notify the main goroutine that the shutdown is complete
	done <- true
}

func main() {
	if err := godotenv.Load(); err != nil {
		log.Println("No .env file found, using defaults")
	}

	// Define flags
	seed := flag.Bool("seed", false, "seed the database with fruit data")
	flag.Parse()

	httpServer, serverInstance := server.NewServer()

	// Handle seeding if flag is set
	if *seed {
		ctx := context.Background()
		log.Println("Running migrations...")
		if err := serverInstance.Repo.Migrate(ctx); err != nil {
			log.Fatalf("Migration failed: %v", err)
		}

		log.Println("Seeding database...")
		if err := serverInstance.FruitSvc.Seed(ctx); err != nil {
			log.Fatalf("Seeding failed: %v", err)
		}
		log.Println("Seeding complete.")

		// If you want it to exit after seeding, uncomment the next line
		// os.Exit(0)
	}

	// Create a done channel to signal when the shutdown is complete
	done := make(chan bool, 1)

	// Run graceful shutdown in a separate goroutine
	go gracefulShutdown(httpServer, serverInstance, done)

	fmt.Printf("Server starting on http://localhost%s\n", httpServer.Addr)
	fmt.Printf("Example query: http://localhost%s/search?q=sweet+yellow+fruit\n", httpServer.Addr)

	err := httpServer.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		panic(fmt.Sprintf("http server error: %s", err))
	}

	// Wait for the graceful shutdown to complete
	<-done
	log.Println("Graceful shutdown complete.")
}

package server

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	"vector-search-project/internal/controller"
	"vector-search-project/internal/database"
	"vector-search-project/internal/repository"
	"vector-search-project/internal/service"
)

type Server struct {
	port int
	db   database.Service
}

func NewServer() *http.Server {
	portStr := os.Getenv("PORT")
	if portStr == "" {
		portStr = "8080"
	}
	port := 8080
	fmt.Sscanf(portStr, "%d", &port)

	db := database.New()

	newServer := &Server{
		port: port,
		db:   db,
	}

	ctx := context.Background()

	// Initialize repositories and services
	fruitRepo := repository.NewFruitRepository(db.Pool())
	embedSvc := service.NewEmbeddingService()
	fruitSvc := service.NewFruitService(fruitRepo, embedSvc)
	fruitCtrl := controller.NewFruitController(fruitSvc)

	// Run migrations and seed data
	if err := fruitRepo.Migrate(ctx); err != nil {
		log.Printf("migration failed: %v", err)
	}
	if err := fruitSvc.Seed(ctx); err != nil {
		log.Printf("seeding failed: %v", err)
	}

	// Declare Server config
	server := &http.Server{
		Addr:         fmt.Sprintf(":%d", newServer.port),
		Handler:      newServer.RegisterRoutes(fruitCtrl),
		IdleTimeout:  time.Minute,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	return server
}

package server

import (
	"fmt"
	"net/http"
	"os"
	"time"

	"vector-search-project/internal/controller"
	"vector-search-project/internal/database"
	"vector-search-project/internal/repository"
	"vector-search-project/internal/service"
)

type Server struct {
	port     int
	db       database.Service
	FruitSvc service.FruitService
	Repo     repository.FruitRepository
}

func (s *Server) DB() database.Service {
	return s.db
}

func NewServer() (*http.Server, *Server) {
	portStr := os.Getenv("PORT")
	if portStr == "" {
		portStr = "8080"
	}
	port := 8080
	fmt.Sscanf(portStr, "%d", &port)

	db := database.New()

	newServer := &Server{
		port: port,
		db:   db,
	}

	// Initialize repositories and services
	fruitRepo := repository.NewFruitRepository(db.Pool())
	embedSvc := service.NewEmbeddingService()
	fruitSvc := service.NewFruitService(fruitRepo, embedSvc)
	fruitCtrl := controller.NewFruitController(fruitSvc)

	newServer.FruitSvc = fruitSvc
	newServer.Repo = fruitRepo

	// Declare Server config
	server := &http.Server{
		Addr:         fmt.Sprintf(":%d", newServer.port),
		Handler:      newServer.RegisterRoutes(fruitCtrl),
		IdleTimeout:  time.Minute,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	return server, newServer
}
